#include <bits/stdc++.h>
using namespace std;
const int N = 10005;
int n,a;
bitset <N> ans,num;
int main(){
    scanf("%d",&n);
    ans.set();
    for(int i = 1;i <= n;i++){
        num.reset();
        num.set(0);
        scanf("%d",&a);
        while(a > 0){
            num |= (num << a);
            scanf("%d",&a);
        }
        ans &= num;
    }
    for(int i = 10000;i >= 0;i--) if(ans[i]){
        printf("%d\n",i);
        return 0;
    }
    return 0;
}
